<script setup>
import { reactive,computed } from 'vue'; import { useRoute,useRouter } from 'vue-router'; import { getPost,createPost,updatePost } from '../services/postService.js'
const route=useRoute(),router=useRouter(),editing=computed(()=>Boolean(route.params.id)),old=editing.value?getPost(route.params.id):null
const form=reactive({category:old?.category||'관광지',title:old?.title||'',content:old?.content||'',password:old?.password||''})
function submit(){if(!form.title.trim()||!form.content.trim()||form.password.length<4){alert('제목, 내용, 4자리 이상의 비밀번호를 입력해 주세요.');return} const post=editing.value?updatePost(route.params.id,{...form}):createPost({...form});router.push(`/board/${post.id}`)}
</script>
<template><div class="page"><div class="page-heading"><div><div class="breadcrumb">홈 &gt; 커뮤니티 &gt; {{editing?'수정':'글쓰기'}}</div><h1>게시글 {{editing?'수정':'작성'}}</h1><p>지역 주민과 관광객에게 도움이 되는 정보를 공유해 주세요.</p></div></div><form class="form-card" @submit.prevent="submit"><label>카테고리<select v-model="form.category"><option>관광지</option><option>문화시설</option><option>레포츠</option><option>숙박</option><option>쇼핑</option><option>여행코스</option><option>축제·행사</option></select></label><label>제목<input v-model="form.title" placeholder="제목을 입력하세요"></label><label>내용<textarea v-model="form.content" placeholder="지역 정보나 방문 경험을 입력하세요"></textarea></label><label>수정용 비밀번호<input v-model="form.password" type="password" placeholder="4자리 이상 입력"><small>수정·삭제 때 필요하며 교육용 설계에 따라 브라우저에 저장됩니다.</small></label><div class="form-actions"><RouterLink class="btn ghost" to="/board">취소</RouterLink><button class="btn primary">저장</button></div></form></div></template>
